/* Libraries, Definitions and Global Declarations */
#include "main.h"
#include "EngTrModel.h"
#include "functions.h"
#include "ports.h"
#include "timer.h"
#include "uart.h"
#include <stdio.h>

volatile double brake_torque = 0;

void TIM3_IRQHandler(void) {
  if (TIM3->SR & (0x1UL << 0U)) {
    TIM3->SR &= ~(0x1UL << 0U);

    EngTrModel_U.Throttle = 1.5f + ((float)adc_value / 4095.0f) * 98.5f;
    EngTrModel_U.BrakeTorque = brake_torque;
    EngTrModel_step();
  }
}

int main(void) {

  SystemClock_Config();
  USART2_Init();
  ADC1_GPIO_Init();
  ADC1_Init();
  TIM3_Init();
  TIM3_40ms_Interrupt_Config();
  EXT_Button_Init();
  EngTrModel_initialize();

  for (;;) {
    if (EXT_BUTTON) {
      Delay_10ms_CPU();
      if (EXT_BUTTON) {
        printf("Button pressed!...\r\n");
        brake_torque = 100.0;
      }
    } else {
      brake_torque = 0;
    }

    printf("Vehicle Speed: %f\r\n", EngTrModel_Y.VehicleSpeed);
    printf("Engine Speed: %f\r\n", EngTrModel_Y.EngineSpeed);
    printf("Gear: %f\r\n", EngTrModel_Y.Gear);
  }
}
